const { spawn } = require('child_process');
const item = $input.first().json;
function runNode(scriptPath, args) {
  return new Promise((resolve, reject) => {
    const child = spawn('node', [scriptPath, ...args], { cwd: item.repoDir, stdio: ['ignore', 'pipe', 'pipe'] });
    let stdout = ''; let stderr = ''; const maxOutput = 1024 * 1024 * 20;
    child.stdout.on('data', (chunk) => { stdout += chunk.toString('utf8'); if (stdout.length > maxOutput) stdout = stdout.slice(-maxOutput); });
    child.stderr.on('data', (chunk) => { stderr += chunk.toString('utf8'); if (stderr.length > maxOutput) stderr = stderr.slice(-maxOutput); });
    child.on('error', reject);
    child.on('close', (code, signal) => {
      if (code === 0) { resolve({ stdout, stderr }); return; }
      const detail = [stdout, stderr].filter(Boolean).join('\n').trim();
      reject(new Error('Presentation extraction failed with exit code ' + code + (signal ? ' signal ' + signal : '') + (detail ? ':\n' + detail : '')));
    });
  });
}
const result = await runNode(item.repoDir + '/tools/video-composer/extract-presentation.mjs', [item.extractJobPath]);
return [{ json: { ...item, extractStdout: result.stdout, extractStderr: result.stderr } }];

